var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":null,"text":{"KOREA":"오랜 고민 끝에, 당신은 한 가지 중요한 사실을 깨달았다.","JPN":"長い間悩んだ結果、あなたは一つ大事なことに気づいた。","ENG":"After much debate, you came to the conclusion","TWN":"苦惱許久後，你意識到一個重要的事實。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":null,"text":{"KOREA":"줄곧 생각해 온 그녀야말로, 앞으로 마주할 운명에서 꼭 필요한 존재라는 것을.","JPN":"ずっと考えてきた彼女だからこそ、これから向き合う運命に必ず必要な存在であることを。","ENG":"that this employee, whom you'd been giving a lot of thought to, was absolutely necessary for the future ahead.","TWN":"一直盤踞在腦海中的她，是你在未來必須要面對的命運中，一個不可或缺的存在。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":null,"text":{"KOREA":"그리하여 당신은 결심했다.","JPN":"そして、あなたは決心した。","ENG":"So, you've decided","TWN":"所以你決定了。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":null,"text":{"KOREA":"이 세계에서 어떤 결말을 마주하더라도, 마지막까지 그녀와 함께하기로.","JPN":"この世界でどのような結末を迎えるとしても、最後まで彼女とともにいることを。","ENG":"that you'll be with her, no matter the consequences.","TWN":"不管這個世界會迎來怎樣的結局，你都要和她一起走到最後。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L7_1","type":"dialog","speaker":null,"text":{"KOREA":"마음의 준비를 마치고 사장실로 호출하자, 곧 도착한다는 응답이 돌아왔다.","JPN":"意を決して社長室へ呼び出すと、もうすぐ着くとの応答が返ってきた。","ENG":"Having decided that, you called her to your office. She said she'd be here soon.","TWN":"下定決心後，你呼叫她到老闆辦公室，得到回應說她馬上就到。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L13_1","type":"dialog","speaker":"BASSOON_HARMONY_NULL_NULL","text":{"KOREA":"나는 알 수 있어.","JPN":"私にはわかるわ。","ENG":"I can tell.","TWN":"我知道。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BASSOON_HARMONY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"BASSOON_HARMONY_NULL_NULL","text":{"KOREA":"당신도 우리와 마찬가지로 죄 많은 사람이라는 걸.","JPN":"あなたも私たちと同じで罪深い人だってことが。","ENG":"That you, like us, are a sinful person.","TWN":"你和我們一樣也是罪孽深重的人。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BASSOON_HARMONY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"BASSOON_HARMONY_NULL_NULL","text":{"KOREA":"……왜 그렇게 생각하냐고?","JPN":"……どうしてそう思うのかって？","ENG":"...Why do I think so?","TWN":"……我為什麼會這麼想？"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BASSOON_HARMONY_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"BASSOON_HARMONY_NULL_NULL","text":{"KOREA":"당신 주위에는 항상 비가 내리니까.","JPN":"あなたの周りにはいつも雨が降っているから。","ENG":"Because it is always raining around you.","TWN":"因為你的周圍總是會下雨。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BASSOON_HARMONY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"BASSOON_HARMONY_NULL_NULL","text":{"KOREA":"아주 어둡고… 차가운 물안개를 일으키는 비가.","JPN":"とても暗くて……冷たい霧を生む雨がね。","ENG":"Rain that... creates this gloomy, icy mist.","TWN":"使周圍變暗……引起冰冷霧水的雨。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BASSOON_HARMONY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"BASSOON_HARMONY_NULL_NULL","text":{"KOREA":"혼자서 많은 것을 짊어지고 있었지?","JPN":"一人で多くのことを背負っていたでしょう？","ENG":"You carry a lot of burden by yourself, don't you?","TWN":"你一定獨自背負著很多東西吧？"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BASSOON_HARMONY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"BASSOON_HARMONY_NULL_NULL","text":{"KOREA":"무언가를 짊어지고 있는지는 사람마다 달라.","JPN":"何を背負っているかは、人によって違うわ。","ENG":"What people carry differs for each person.","TWN":"每個人都背負著不同的東西。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BASSOON_HARMONY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"BASSOON_HARMONY_NULL_NULL","text":{"KOREA":"죄책감일 수도 있고, 책임감일 수도 있고, 어떤 사람은 사명감이기도 했어.","JPN":"罪悪感かもしれないし、責任感かもしれない。使命感という人もいたわね。","ENG":"It could be guilt, a sense of responsibility, or for some, a sense of duty.","TWN":"可能是罪惡感，可能是責任感，也有可能是使命感。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BASSOON_HARMONY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"BASSOON_HARMONY_NULL_NULL","text":{"KOREA":"하지만 사람은 그렇게 강인하지 않아. 내 연주를 들은 이들이 금방 참을성을 잃는 것처럼.","JPN":"でも、人はそう強くはないわ。私の演奏を聞いた人がすぐに耐えられなくなるように。","ENG":"But people are not as strong as they think. Much like those who lose their patience after hearing my performance.","TWN":"但人類並沒有那麼堅強，所以聽到我的演奏的人都會很快就失去耐性。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BASSOON_HARMONY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"BASSOON_HARMONY_NULL_NULL","text":{"KOREA":"결국 늦든, 빠르든.","JPN":"結局のところ、遅かれ早かれ。","ENG":"Whether it's fast or slow.","TWN":"無論早或晚，"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BASSOON_HARMONY_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"BASSOON_HARMONY_NULL_NULL","text":{"KOREA":"갑작스럽든, 예정되었든. 모든 것과 작별하고 싶은 시기가 오고 말아.","JPN":"突然であれ、予定されていたことであれ。すべてに別れを告げたくなる時がやってきてしまう。","ENG":"Sudden or expected. The time when one wants to part with everything eventually arrives.","TWN":"事發突然或是早有預兆，終究會有想跟一切告別的時候來臨。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BASSOON_HARMONY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"BASSOON_HARMONY_NULL_NULL","text":{"KOREA":"그러지 않으려는 사람들은…. 결국 덜어내는 방법을 배우게 돼.","JPN":"それを避けようとする人も……結局は楽になる方法を身につけるようになるわ。","ENG":"For those who try not to... they learn how to lessen it.","TWN":"有些人不希望這種事發生…因此會學會減輕自己肩上的負擔。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BASSOON_HARMONY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"BASSOON_HARMONY_NULL_NULL","text":{"KOREA":"스스로 짊어진 것들에 짓눌리지 않기 위해.","JPN":"自分が背負っているものに押しつぶされないようにね。","ENG":"To avoid being crushed by their burden.","TWN":"才不會讓那些所謂的責任把自己壓得喘不過氣。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BASSOON_HARMONY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"BASSOON_HARMONY_NULL_NULL","text":{"KOREA":"그런데도 당신은…. 아직 포기하지 않았어.","JPN":"それなのにあなたという人は……まだ諦めていない。","ENG":"And yet, you... still have not given up.","TWN":"但是你……依然沒有放棄。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BASSOON_HARMONY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"BASSOON_HARMONY_NULL_NULL","text":{"KOREA":"오히려 주변에서 다가올 수 없게, 늘 빗속에서 홀로 머물고 있지.","JPN":"むしろ周りを寄せ付けないように、いつも雨の中にひとり留まっているわ。","ENG":"Better yet, you stay in the rain alone so no one else can come near.","TWN":"你反而選擇在雨中獨處，拒絕周圍的人靠近。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BASSOON_HARMONY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"BASSOON_HARMONY_NULL_NULL","text":{"KOREA":"괜찮아. 이제부터는 내가 곁에 있어 줄게.","JPN":"大丈夫よ。これからは私がそばに居てあげる。","ENG":"It's okay. I will be by your side from now on.","TWN":"沒關係，從今以後，我會陪在你身邊。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BASSOON_HARMONY_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"BASSOON_HARMONY_NULL_NULL","text":{"KOREA":"나는 당신의 비, 당신의 안개. 당신의 죽음.","JPN":"私はあなたの雨、あなたの霧。そして、あなたの死。","ENG":"I will be your rain, your mist, and your death.","TWN":"我是你的雨、你的霧、你的死亡。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BASSOON_HARMONY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"BASSOON_HARMONY_NULL_NULL","text":{"KOREA":"마지막 작별을 갈구할 때, 나는 당신 곁에 준비되어 있을 테니까.","JPN":"最後に死を切望する時、私はそばにちゃんと居るから。","ENG":"For when you crave your last goodbye, I will be ready by your side.","TWN":"在你渴望最後的道別時，我會在你身邊做好準備。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BASSOON_HARMONY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};